#!/usr/bin/env node
// Parses a "case-submission" GitHub issue body, writes a JSON data file,
// and regenerates the static accidents data index consumed by the front app.

import { mkdirSync, readdirSync, unlinkSync, writeFileSync } from 'node:fs'
import { resolve } from 'node:path'

const ROOT = process.cwd()
const DATA_DIR = resolve(ROOT, 'apps/front/data')
const INDEX_FILE = resolve(
  ROOT,
  'apps/front/src/static/accidents-data.generated.ts',
)

const BEGIN = '<!-- BEGIN_CASE_DATA -->'
const END = '<!-- END_CASE_DATA -->'

const body = process.env.ISSUE_BODY ?? ''
const issueNumber = String(process.env.ISSUE_NUMBER ?? '').trim()
const issueUrl = process.env.ISSUE_URL ?? ''

if (!issueNumber) {
  console.error('ISSUE_NUMBER env var is required')
  process.exit(1)
}

const beginIdx = body.indexOf(BEGIN)
const endIdx = body.indexOf(END)
if (beginIdx < 0 || endIdx < 0 || endIdx < beginIdx) {
  console.error('Could not find case data markers in issue body. Skipping.')
  process.exit(0)
}

const block = body.slice(beginIdx + BEGIN.length, endIdx)
const jsonMatch = block.match(/```json\s*([\s\S]*?)```/)
if (!jsonMatch) {
  console.error('Could not find JSON code block. Skipping.')
  process.exit(0)
}

let draft
try {
  draft = JSON.parse(jsonMatch[1])
} catch (err) {
  console.error('Failed to parse JSON:', err.message)
  process.exit(1)
}

const slug =
  String(draft.companyName || 'unknown')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[^\p{L}\p{N}]+/gu, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 60) || 'unknown'

const year = String(draft.date || '').slice(0, 4) || 'unknown'
const padded = issueNumber.padStart(3, '0')
const filename = `${padded}-${slug}-${year}.json`

const accident = {
  id: issueNumber,
  ...draft,
  createdAt: new Date().toISOString(),
  issueUrl,
}

mkdirSync(DATA_DIR, { recursive: true })

// Remove any stale entry for this issue (e.g., on issue edits with new slug/year).
for (const existing of readdirSync(DATA_DIR)) {
  if (existing.startsWith(`${padded}-`) && existing !== filename) {
    unlinkSync(resolve(DATA_DIR, existing))
  }
}

writeFileSync(
  resolve(DATA_DIR, filename),
  `${JSON.stringify(accident, null, 2)}\n`,
)

const allFiles = readdirSync(DATA_DIR)
  .filter((f) => f.endsWith('.json'))
  .sort()

const lines = [
  '// AUTO-GENERATED FILE — do not edit by hand.',
  '// Regenerated by .github/workflows/case-submission.yml when a new case is submitted.',
  '',
]
allFiles.forEach((file, i) => {
  lines.push(`import accident${i} from '../../data/${file}'`)
})
lines.push('')
lines.push("import type { Accident } from './accidents'")
lines.push('')
lines.push('export const ACCIDENT_DATA: Accident[] = [')
allFiles.forEach((_, i) => {
  lines.push(`  accident${i} as Accident,`)
})
lines.push(']')

writeFileSync(INDEX_FILE, `${lines.join('\n')}\n`)
